SELECT [NavisionEan-step0].[Item No_], [NavisionEan-step0].[Cross-Reference Type], [NavisionEan-step0].[Cross-Reference No_] AS EANCode, [NavisionEan-step0-UPC].[Cross-Reference No_] AS UPCCode, Item.No_ AS Item, Item.[Model Item No_] AS Article, Item.[Variable Code 01] AS Color, [Variable Code_1].Description AS [Size], Item.[Season Code], Item.[Trademark Code], Item.[Configurator Relation], [Purchase Line].[Document No_], Sum(Val([quantity])) AS qty, Item.[Description 2], [Variable Code].Description AS ColorDescription
FROM (((((Item LEFT JOIN [NavisionEan-step0] ON Item.No_ = [NavisionEan-step0].[Item No_]) LEFT JOIN [Variable Code] ON (Item.[Variable Group 01] = [Variable Code].[Variable Group]) AND (Item.[Variable Code 01] = [Variable Code].[Variable Code])) INNER JOIN [Purchase Line] ON Item.No_ = [Purchase Line].No_) LEFT JOIN [NavisionEan-step0-UPC] ON Item.No_ = [NavisionEan-step0-UPC].[Item No_]) INNER JOIN [Purchase Header] ON [Purchase Line].[Document No_] = [Purchase Header].No_) LEFT JOIN [Variable Code] AS [Variable Code_1] ON (Item.[Variable Code 02] = [Variable Code_1].[Variable Code]) AND (Item.[Variable Group 02] = [Variable Code_1].[Variable Group])
WHERE ((([Purchase Line].[Delete Reason])=""))
GROUP BY [NavisionEan-step0].[Item No_], [NavisionEan-step0].[Cross-Reference Type], [NavisionEan-step0].[Cross-Reference No_], [NavisionEan-step0-UPC].[Cross-Reference No_], Item.No_, Item.[Model Item No_], Item.[Variable Code 01], [Variable Code_1].Description, Item.[Season Code], Item.[Trademark Code], Item.[Configurator Relation], [Purchase Line].[Document No_], Item.[Description 2], [Variable Code].Description, [Variable Code].Description, [Purchase Header].No_
HAVING (((Item.[Configurator Relation])=3) AND (([Purchase Header].No_)=[forms]![principale]![filtroodaean]));

